#![expect(clippy::unwrap_used)] // build tool, so okay here

/// Docs read from `/docs`
mod docs;

/// Examples read from `/examples`
mod examples;

/// Python API reference generated by mkdocs
mod python;

/// C++ API reference generated by Doxygen
mod cpp;

use std::borrow::Cow;
use std::cell::{Cell, RefCell};
use std::io::IsTerminal as _;
use std::time::Duration;

use camino::Utf8Path;
use cargo_metadata::Package;
use cargo_metadata::semver::Version;
use indicatif::{MultiProgress, ProgressBar};

pub fn run(release_version: Option<Version>) -> anyhow::Result<Vec<Document>> {
    let ctx = Context::new(release_version)?;
    docs::ingest(&ctx)?;
    examples::ingest(&ctx)?;
    python::ingest(&ctx)?;
    cpp::ingest(&ctx)?;
    Ok(ctx.finish())
}

struct Context {
    progress: MultiProgress,
    metadata: cargo_metadata::Metadata,
    id_gen: IdGen,
    documents: RefCell<Vec<Document>>,
    release_version: Option<Version>,
    is_tty: bool,
}

impl Context {
    fn new(release_version: Option<Version>) -> anyhow::Result<Self> {
        Ok(Self {
            progress: MultiProgress::new(),
            metadata: re_build_tools::cargo_metadata()?,
            id_gen: IdGen::new(),
            documents: RefCell::new(Vec::new()),
            release_version,
            is_tty: std::io::stdout().is_terminal(),
        })
    }

    fn is_tty(&self) -> bool {
        self.is_tty
    }

    fn progress_bar(&self, prefix: impl Into<Cow<'static, str>>) -> ProgressBar {
        let bar = ProgressBar::new_spinner().with_prefix(prefix);
        bar.enable_steady_tick(Duration::from_millis(100));
        #[expect(clippy::literal_string_with_formatting_args)]
        bar.set_style(bar.style().template("{spinner} {prefix}: {msg}").unwrap());
        self.progress.add(bar)
    }

    #[expect(clippy::needless_pass_by_value)]
    fn finish_progress_bar(&self, bar: ProgressBar) {
        bar.disable_steady_tick();
        bar.finish_and_clear();
        self.progress.remove(&bar);
        let _ = bar;
    }

    fn workspace_root(&self) -> &Utf8Path {
        &self.metadata.workspace_root
    }

    fn rerun_pkg(&self) -> &Package {
        self.metadata
            .packages
            .iter()
            .find(|pkg| pkg.name.as_str() == "rerun")
            .unwrap()
    }

    fn release_version(&self) -> &Version {
        self.release_version
            .as_ref()
            .unwrap_or_else(|| &self.rerun_pkg().version)
    }

    fn push(&self, data: DocumentData) {
        let weight = data.kind.weight();
        self.push_weighted(data, weight);
    }

    fn push_weighted(&self, mut data: DocumentData, weight: u64) {
        // `page` is the distinct attribute: docs sections share their parent
        // page's URL so search shows at most one (the best) section per page,
        // while every other document keeps a unique value and is unaffected.
        if data.page.is_none() {
            data.page = Some(data.url.clone());
        }
        self.documents.borrow_mut().push(Document {
            id: self.id_gen.next(),
            weight,
            data,
        });
    }

    fn finish(self) -> Vec<Document> {
        let documents = self.documents.into_inner();
        println!("collected {} documents", documents.len());
        documents
    }
}

#[derive(serde::Serialize, serde::Deserialize)]
pub struct Document {
    id: u64,

    /// Page-type ranking weight, used by the `weight:desc` ranking rule
    /// so that guides and examples rank above individual API symbols.
    #[serde(default)]
    weight: u64,
    #[serde(flatten)]
    data: DocumentData,
}

impl Document {
    pub const PRIMARY_KEY: &'static str = "id";

    pub fn title(&self) -> &String {
        &self.data.title
    }

    pub fn url(&self) -> &String {
        &self.data.url
    }

    pub fn content(&self) -> &String {
        &self.data.content
    }
}

#[derive(Debug, serde::Serialize, serde::Deserialize)]
struct DocumentData {
    kind: DocumentKind,
    title: String,
    hidden_tags: Vec<String>,
    tags: Vec<String>,
    content: String,
    url: String,

    /// Deduplication key (Meilisearch `distinctAttribute`). Defaults to `url`
    /// in [`Context::push`]; docs sections set it to their parent page URL.
    #[serde(default)]
    page: Option<String>,

    /// For docs sections: the title of the page the section belongs to.
    /// Display-only (NOT searchable — see the settings in `meili.rs`).
    #[serde(skip_serializing_if = "Option::is_none", default)]
    page_title: Option<String>,

    /// Thumbnail shown next to the result in the website's search dialog.
    #[serde(skip_serializing_if = "Option::is_none", default)]
    image: Option<String>,
}

#[derive(Clone, Copy, Debug, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "snake_case")]
enum DocumentKind {
    Docs,
    Examples,
    Python,
    Cpp,
}

impl DocumentKind {
    /// Page-type ranking weight for the `weight:desc` ranking rule (see
    /// [`weight`] for the full scale and rationale).
    ///
    /// Only kinds pushed via [`Context::push`] read their weight from here.
    /// Docs vary the weight per document (page intro vs. section vs. migration
    /// guide) and push it explicitly via [`Context::push_weighted`], so the
    /// [`Self::Docs`] arm below is only a sensible default.
    fn weight(self) -> u64 {
        match self {
            Self::Docs => weight::DOCS_PAGE,
            Self::Examples => weight::EXAMPLE,
            Self::Python | Self::Cpp => weight::API_SYMBOL,
        }
    }
}

/// Page-type ranking weights for the `weight:desc` ranking rule (configured in
/// [`meili`](super::meili)). Every weight lives here so the scale stays
/// mutually consistent and can be tuned in one place.
///
/// The rule runs *after* word/typo/proximity/attribute matching, so these only
/// break ties between comparably-good matches: whole-page guides beat the
/// thousands of per-symbol API documents for generic queries, while an exact
/// symbol match still wins afterwards on `exactness`.
pub mod weight {
    /// A documentation page's own intro. Represents the whole page, so it beats
    /// another page's niche section for a bare term.
    pub const DOCS_PAGE: u64 = 10;

    /// A documentation `##`/`###` section. Ties [`EXAMPLE`] on purpose.
    pub const DOCS_SECTION: u64 = 9;

    /// An example or example category. Ties docs sections ([`DOCS_SECTION`]):
    /// for a query naming an example or integration (`urdf`, `ros`, `lerobot`)
    /// the example's exact-match title then wins on `exactness`, while concept
    /// queries (`transform`, `video`) have no competing example and stay
    /// docs-first.
    pub const EXAMPLE: u64 = 9;

    /// A migration-guide title (migration guides are indexed title-only).
    /// Below examples, so they stay findable by version or name but stop
    /// outranking real guides on the common terms in their body.
    pub const MIGRATION: u64 = 6;

    /// An individual API symbol (Python/C++). These outnumber docs pages ~27:1,
    /// so they sit far below page-level content to avoid drowning generic
    /// queries.
    pub const API_SYMBOL: u64 = 3;
}

/// Remove HTML tags (e.g. the `<picture>`/`<img>` embeds in docs and example
/// READMEs) so attribute soup like `srcset="…1024w.png"` neither pollutes
/// search matching nor leaks into result excerpts on the website.
pub fn strip_html_tags(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut in_tag = false;
    for c in s.chars() {
        match c {
            '<' => {
                in_tag = true;
                // Tags act as word boundaries.
                out.push(' ');
            }
            '>' if in_tag => in_tag = false,
            c if !in_tag => out.push(c),
            _ => {}
        }
    }
    out
}

struct IdGen {
    v: Cell<u64>,
}

impl IdGen {
    fn new() -> Self {
        Self { v: Cell::new(0) }
    }

    fn next(&self) -> u64 {
        self.v.replace(self.v.get() + 1)
    }
}
